VALUES
  ('judicial-d35ec6db-moex-00077', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲以其所有之 A 地設定普通抵押權於乙，用以擔保其對乙所負借款債務之履行。關於甲於 A 地 設定抵押權後之權利，下列敘述何者錯誤？', '["甲得移轉A地所有權於第三人", "甲得以A地設定後次序之抵押權於第三人", "甲得將A地出租於第三人", "甲得聲請法院拍賣抵押之A地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00078', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲有經登記之A地，遭好友乙惡意占有並建B屋居住達18年，經甲發現後向法院訴請拆屋還地， 經乙求情後，甲撤回起訴，乙卻繼續占有 A 地經 3 年不願返還，甲無奈再次向法院訴請拆屋還 地。下列敘述何者正確？', '["乙公然和平繼續占有A地期間，受占有保護規定而成為有權占有", "乙得請求登記為A地所有人", "乙得請求登記為A地地上權人", "乙得請求登記為A地不動產役權人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00079', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者無過失時，亦應負損害賠償責任？', '["判決離婚時無過失之一方", "婚姻撤銷時無過失之一方", "善意且無過失之重婚者", "婚約解除時無過失之一方"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00080', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲、乙為兄弟，均已喪妻。甲有丙、丁二子，均尚未成年，乙有一女戊。乙擬收養5歲之丁。甲 代理丁與乙於民國111年2月1日合意丁被乙收養，於同年3月1日在公證人處完成書面契約， 同年4月1日向地方法院提出聲請，法院認可收養之裁定於同年10月1日確定。依民法規定， 乙、丁之收養契約何時生效？', '["民國111年2月1日", "民國111年3月1日", "民國111年4月1日", "民國111年10月1日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00081', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲、乙為夫妻，有一成年之子丙，丁為甲之父。乙、丙、丁均不能維持生活又無謀生能力，甲有 扶養能力。何人得優先受甲扶養？', '["乙丙", "乙丁", "丙丁", "乙丙丁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00082', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於遺產繼承人之敘述，何者正確？', '["甲、乙為夫妻，同時遇難死亡，若無第一順位繼承人，則甲之父母僅得繼承甲之遺產，乙之父 母僅得繼承乙之遺產", "父母離婚，父與他人再婚，喪失對於其原生子女遺產之繼承權", "本生父母對於已出養子女之遺產，因仍具血緣關係，享有繼承權", "繼父對於妻之前夫所生之子女，因已共居日久，所以具備法律上之親子關係，對該子女之遺產 有繼承權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00083', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '得知離家數年之庚死亡時，庚配偶戊以為自己是唯一繼承人。未料，竟有丁出面主張庚其實已與 他多年如同夫妻般共同生活。關於庚之遺產，下列敘述何者正確？', '["喪葬費用應由法定繼承人支出，以免影響到庚遺產之正確數額", "如庚生前繼續扶養丁，丁得經程序主張受酌給遺產", "戊得主張遺產酌給請求權", "丁有事實上配偶之地位，與戊各得分配二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00084', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲有子女乙、丙、丁。甲於遺囑中委託好友戊指定甲之遺囑執行人。甲死亡後，下列敘述何者正確？', '["戊若已死亡，丁得逕向法院聲請指定遺囑執行人", "戊得指定自己16歲之兒子庚為遺囑執行人", "戊得指定丙26歲之兒子癸為遺囑執行人", "戊得指定自己76歲但受輔助宣告之媽媽辛為遺囑執行人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00085', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-f335c5ad', 'sub-judicial-d35ec6db-02', NULL, 'essay', '甲取得法院准許拍賣債務人乙所有抵押物 A屋之裁定（擔保新臺幣（下
同）1000萬元債權）。甲以此向法院聲請對乙之 A屋強制執行並獲准許，
試問如 A屋拍賣所得之價金僅 700 萬元，甲可否以拍賣抵押物裁定向法
院聲請就乙所有之其他財產 B 屋強制執行？倘若 A 屋經法院核定最低
拍賣底價為 1400 萬元，登記簿第二順位 500 萬元抵押權人丙未聲明參
與分配，法院應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ca59765025ff", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0412", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00086', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-f335c5ad', 'sub-judicial-d35ec6db-02', NULL, 'essay', '乙合夥團體現行合夥人有 A、B、C。甲對乙合夥團體取得新臺幣（下同）
300 萬元貨款勝訴確定判決，甲向執行法院聲請強制執行，但合夥財產
僅 200 萬元，試問甲可否以該確定判決對 A、B、C 之私人財產執行？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ca59765025ff", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0412", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
